import React, { useEffect } from 'react';
import Hero from '../components/Hero';
import './Home.css';

const Home = () => {
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  return (
    <main>
      <Hero />
      {/* We'll add more sections later */}
      <section className="section" style={{ height: '50vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <h2 style={{ color: '#dc2626' }}>More sections coming soon...</h2>
      </section>
    </main>
  );
};

export default Home;
